def run_code_generation(task: str, max_iterations: int = 5):
    user_proxy.initiate_chat(
        manager,
        message=f"Generate code for: {task}"
    )

    for i in range(max_iterations):
        last_messages = groupchat.messages[-3:]  # Last 3 exchanges
        if 'PASS' in last_messages[-1]['content']:
            print(f"✓ Code validated after {i+1} iterations")
            break

        feedback = tester.generate_reply(last_messages)
        user_proxy.send(recipient=manager, message=f"Refine based on: {feedback}")

    return groupchat.messages[-1]['content']

import ast
import re

def validate_code_safety(code: str) -> dict:
    tree = ast.parse(code)

    dangers = {
        'system_calls': bool(re.search(r'\b(?:os|subprocess|exec|eval|open)\b', code)),
        'network': bool(re.search(r'\b(?:requests|urllib|socket|http)\b', code)),
        'credentials': bool(re.search(r'(api_key|password|secret|token)=["\'][^"\']+["\']', code)),
        'file_writes': any(isinstance(node, ast.Call) and 
                          any(isinstance(arg, ast.Str) and 'w' in arg.s for arg in node.args) 
                          for node in ast.walk(tree))
    }

    return {'safe': not any(dangers.values()), 'issues': dangers}

