def vex_safe_execute(code: str, context: dict) -> dict:
    # Pre-execution Vex scan
    exec_verification = vex_client.verify({
        "content": code,
        "context": context,
        "policies": [
            "execution-sandboxing",
            "dependency-safety",
            "no-system-calls",
            "timeout-protection"
        ]
    })

    if not exec_verification.passed:
        return {
            'success': False,
            'error': 'Vex blocked unsafe execution',
            'issues': exec_verification.issues
        }

    # Safe execution only after Vex approval
    return safe_execute(code)

