class VexGroupChat(GroupChat):
    def __init__(self, *args, max_turns=20, token_budget=10000, **kwargs):
        super().__init__(*args, **kwargs)
        self.max_turns = max_turns
        self.token_budget = token_budget
        self.turn_count = 0
        self.tokens_used = 0

    def append(self, message, **kwargs):
        if self.turn_count >= self.max_turns:
            raise Exception("Max conversation turns exceeded")

        # Vex conversation health check
        health_check = vex_client.verify({
            "content": message["content"],
            "context": {
                "turn_count": self.turn_count,
                "tokens_used": self.tokens_used,
                "agents_involved": len(self.agents)
            },
            "policies": ["prevent-loops", "convergence-check", "token-budget"]
        })

        if not health_check.passed:
            message["content"] += "\n[VEX: Conversation terminated - loop detected]"

        super().append(message, **kwargs)
        self.turn_count += 1
        self.tokens_used += len(message["content"])

